# Check for discrepancies in CI vs prod requirements
import re

prod_reqs = {}
ci_reqs = {}

with open('requirements.txt') as f:
    for line in f:
        line = line.strip()
        if not line or line.startswith('#'):
            continue
        # Parse package name and version spec
        match = re.match(r'^([a-zA-Z0-9_.-]+)(.*)', line)
        if match:
            prod_reqs[match.group(1).lower()] = line

with open('requirements-ci.txt') as f:
    for line in f:
        line = line.strip()
        if not line or line.startswith('#'):
            continue
        match = re.match(r'^([a-zA-Z0-9_.-]+)(.*)', line)
        if match:
            ci_reqs[match.group(1).lower()] = line

# Check for packages in CI that aren't in prod
print("Packages in CI but not production:")
for pkg in sorted(ci_reqs):
    if pkg not in prod_reqs:
        print(f"  - {ci_reqs[pkg]}")

# Check for major version mismatches
print("\nMajor version discrepancies (prod vs CI):")
for pkg in sorted(prod_reqs):
    if pkg not in ci_reqs:
        # OK if it's only in prod (e.g., transformers, torch)
        continue

    # Extract major version from both
    prod_line = prod_reqs[pkg]
    ci_line = ci_reqs[pkg]

    # Simple check: look for >=X,<Y patterns
    prod_match = re.search(r'>=(\d+)', prod_line)
    ci_match = re.search(r'>=(\d+)', ci_line)

    if prod_match and ci_match:
        prod_major = prod_match.group(1)
        ci_major = ci_match.group(1)
        if prod_major != ci_major:
            print(f"  {pkg}: prod={prod_line} vs ci={ci_line}")
